{
  "name": "Raha Control Center",
  "description": "A modern, enterprise-grade Super Admin Dashboard for the Raha multi-tenant pharmacy management system."
}

export type PharmacyStatus = 'active' | 'suspended' | 'pending';

export interface Pharmacy {
  id: string;
  name: string;
  uniqueKey: string;
  status: PharmacyStatus;
  joinedDate: string; // ISO Date string
  location: string;
  contactEmail: string;
}

export interface AggregatedOrder {
  id: string;
  medicineName: string;
  totalQuantity: number;
  requestingPharmacyIds: string[]; // List of pharmacy IDs requesting this
  status: 'pending' | 'supplied' | 'partial';
  urgency: 'low' | 'medium' | 'high';
}

export interface DashboardStats {
  totalPharmacies: number;
  totalMonthlySales: number;
  totalActiveOrders: number;
  growthRate: number; // Percentage
}

export interface User {
  id: string;
  email: string;
  role: 'super_admin';
}

import { createClient } from '@supabase/supabase-js';

// NOTE: These are placeholder credentials. 
// The backend developer should replace these with actual environment variables.
// e.g. process.env.REACT_APP_SUPABASE_URL
const SUPABASE_URL = 'https://xyzcompany.supabase.co';
const SUPABASE_ANON_KEY = 'public-anon-key';

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

// Helper function example for future use
export const getPharmacies = async () => {
  const { data, error } = await supabase
    .from('pharmacies')
    .select('*');

  if (error) throw error;
  return data;
};

import React from 'react';

interface BadgeProps {
  children: React.ReactNode;
  variant?: 'default' | 'success' | 'warning' | 'danger' | 'neutral';
  className?: string;
}

const Badge: React.FC<BadgeProps> = ({ children, variant = 'default', className = '' }) => {
  const baseClasses = "inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ring-1 ring-inset";

  const variants = {
    default: "bg-blue-50 text-blue-700 ring-blue-700/10",
    success: "bg-green-50 text-green-700 ring-green-600/20",
    warning: "bg-yellow-50 text-yellow-800 ring-yellow-600/20",
    danger: "bg-red-50 text-red-700 ring-red-600/10",
    neutral: "bg-gray-50 text-gray-600 ring-gray-500/10",
  };

  return (
    <span className={`${baseClasses} ${variants[variant]} ${className}`}>
      {children}
    </span>
  );
};

export default Badge;

import React from 'react';
import { Loader2 } from 'lucide-react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost' | 'danger';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
  leftIcon?: React.ReactNode;
}

const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  isLoading, 
  leftIcon,
  className = '', 
  disabled,
  ...props 
}) => {
  const baseClasses = "inline-flex items-center justify-center font-medium rounded-lg transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 focus:ring-indigo-500 shadow-sm",
    secondary: "bg-gray-100 text-gray-900 hover:bg-gray-200 focus:ring-gray-500",
    outline: "bg-white text-gray-700 border border-gray-300 hover:bg-gray-50 focus:ring-indigo-500",
    ghost: "text-gray-600 hover:bg-gray-100 hover:text-gray-900 focus:ring-gray-500",
    danger: "bg-red-600 text-white hover:bg-red-700 focus:ring-red-500 shadow-sm",
  };

  const sizes = {
    sm: "px-3 py-1.5 text-xs",
    md: "px-4 py-2 text-sm",
    lg: "px-6 py-3 text-base",
  };

  return (
    <button 
      className={`${baseClasses} ${variants[variant]} ${sizes[size]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
      {!isLoading && leftIcon && <span className="mr-2">{leftIcon}</span>}
      {children}
    </button>
  );
};

export default Button;

