export default Sidebar;

import React, { useState } from 'react';
import { LockKeyhole, ShieldCheck } from 'lucide-react';
import Button from '../components/ui/Button';
import { SUPER_ADMIN_PIN, APP_NAME } from '../constants';

interface LoginProps {
  onLogin: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    // Simulate API delay
    setTimeout(() => {
      if (pin === SUPER_ADMIN_PIN) {
        onLogin();
      } else {
        setError('Invalid PIN code. Please try again.');
        setIsLoading(false);
      }
    }, 800);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
      <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden">
        <div className="p-8">
          <div className="flex flex-col items-center mb-8">
            <div className="w-16 h-16 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-bold text-gray-900">{APP_NAME}</h1>
            <p className="text-gray-500 text-sm mt-2 text-center">
              Enter your Super Admin PIN to access the dashboard
            </p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label htmlFor="pin" className="block text-sm font-medium text-gray-700 mb-2">
                Security PIN
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <LockKeyhole className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  type="password"
                  id="pin"
                  maxLength={6}
                  value={pin}
                  onChange={(e) => setPin(e.target.value)}
                  className="block w-full pl-10 pr-3 py-3 border border-gray-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500 transition-colors text-lg tracking-widest placeholder-gray-400"
                  placeholder="••••"
                  autoFocus
                />
              </div>
              {error && (
                <p className="mt-2 text-sm text-red-600 flex items-center">
                  <span className="mr-1">●</span> {error}
                </p>
              )}
            </div>

            <Button
              type="submit"
              className="w-full py-3"
              size="lg"
              isLoading={isLoading}
              disabled={pin.length === 0}
            >
              Access Dashboard
            </Button>
          </form>
        </div>
        <div className="px-8 py-4 bg-gray-50 border-t border-gray-100 text-center">
          <p className="text-xs text-gray-400">
            Secure System • Authorized Personnel Only
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState } from 'react';
import { 
  Search, 
  Plus, 
  MoreHorizontal, 
  Filter,
  CheckCircle2,
  XCircle,
  Clock
} from 'lucide-react';
import { MOCK_PHARMACIES } from '../constants';
import Button from '../components/ui/Button';
import Badge from '../components/ui/Badge';
import { Pharmacy, PharmacyStatus } from '../types';

const Pharmacies: React.FC = () => {
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>(MOCK_PHARMACIES);
  const [searchTerm, setSearchTerm] = useState('');

  const handleGenerateKey = () => {
    // Mock functionality
    const randomKey = `KRT-${Math.floor(100 + Math.random() * 900)}`;
    alert(`Generated New Pharmacy Key: ${randomKey}\n\nShare this key with the pharmacy admin to complete registration.`);
  };

  const toggleStatus = (id: string) => {
    setPharmacies(prev => prev.map(p => {
      if (p.id === id) {
        return {
          ...p,
          status: p.status === 'active' ? 'suspended' : 'active'
        };
      }
      return p;
    }));
  };

  const getStatusBadge = (status: PharmacyStatus) => {
    switch (status) {
      case 'active':
        return <Badge variant="success">Active</Badge>;
      case 'suspended':
        return <Badge variant="danger">Suspended</Badge>;
      case 'pending':
        return <Badge variant="warning">Pending</Badge>;
      default:
        return <Badge variant="neutral">{status}</Badge>;
    }
  };

  const filteredPharmacies = pharmacies.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.uniqueKey.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Pharmacies</h1>
          <p className="text-gray-500 mt-1">Manage registered tenants and generate access keys.</p>
        </div>
        <Button onClick={handleGenerateKey} leftIcon={<Plus size={18} />}>
          Generate New Key
        </Button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        {/* Toolbar */}
        <div className="p-4 border-b border-gray-200 flex flex-col sm:flex-row gap-4 justify-between items-center bg-gray-50/50">
          <div className="relative w-full sm:w-96">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <Search className="h-4 w-4 text-gray-400" />
            </div>
            <input
              type="text"
              className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg text-sm placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-colors"
              placeholder="Search by name or ID..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-2 w-full sm:w-auto">
            <Button variant="outline" size="sm" leftIcon={<Filter size={14} />}>
              Filter
            </Button>
            <Button variant="outline" size="sm">
              Export
            </Button>
          </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Pharmacy</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Unique Key</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Location</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Joined Date</th>
                <th scope="col" className="relative px-6 py-3">
                  <span className="sr-only">Actions</span>
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredPharmacies.length > 0 ? (
                filteredPharmacies.map((pharmacy) => (
                  <tr key={pharmacy.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        <div className="flex-shrink-0 h-10 w-10">
                          <div className="h-10 w-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold text-sm">
                            {pharmacy.name.substring(0, 2).toUpperCase()}
                          </div>
                        </div>
                        <div className="ml-4">
                          <div className="text-sm font-medium text-gray-900">{pharmacy.name}</div>
                          <div className="text-sm text-gray-500">{pharmacy.contactEmail}</div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600 font-mono">
                      {pharmacy.uniqueKey}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {pharmacy.location}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      {getStatusBadge(pharmacy.status)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {new Date(pharmacy.joinedDate).toLocaleDateString()}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                       <div className="flex items-center justify-end gap-2">
                         {pharmacy.status === 'active' ? (
                            <button 
                              onClick={() => toggleStatus(pharmacy.id)}
                              className="text-gray-400 hover:text-red-600 transition-colors"
                              title="Suspend"
                            >
                              <XCircle size={18} />
                            </button>
                         ) : pharmacy.status === 'suspended' ? (
                            <button 
                              onClick={() => toggleStatus(pharmacy.id)}
                              className="text-gray-400 hover:text-green-600 transition-colors"
                              title="Activate"
                            >
                              <CheckCircle2 size={18} />
                            </button>
                         ) : (
                            <button className="text-gray-400 cursor-not-allowed">
                               <Clock size={18} />
                            </button>
                         )}
                         <button className="text-gray-400 hover:text-indigo-600 transition-colors">
                           <MoreHorizontal size={18} />
                         </button>
                       </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-gray-500">
                    No pharmacies found matching your search.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination (Static for mock) */}
        <div className="bg-white px-4 py-3 border-t border-gray-200 flex items-center justify-between sm:px-6">
          <div className="hidden sm:flex-1 sm:flex sm:items-center sm:justify-between">
            <div>
              <p className="text-sm text-gray-700">
                Showing <span className="font-medium">1</span> to <span className="font-medium">{filteredPharmacies.length}</span> of <span className="font-medium">{MOCK_PHARMACIES.length}</span> results
              </p>
            </div>
            <div>
              <nav className="relative z-0 inline-flex rounded-md shadow-sm -space-x-px" aria-label="Pagination">
                <button className="relative inline-flex items-center px-2 py-2 rounded-l-md border border-gray-300 bg-white text-sm font-medium text-gray-500 hover:bg-gray-50">
                  Previous
                </button>
                <button className="relative inline-flex items-center px-2 py-2 rounded-r-md border border-gray-300 bg-white text-sm font-medium text-gray-500 hover:bg-gray-50">
                  Next
                </button>
              </nav>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Pharmacies;

import React, { useState } from 'react';
import { 
  PackageCheck, 
  Search, 
  TrendingUp,
  AlertCircle
} from 'lucide-react';
import { MOCK_MARKET_DEMAND, MOCK_PHARMACIES } from '../constants';
import Button from '../components/ui/Button';
import Badge from '../components/ui/Badge';

const MarketDemand: React.FC = () => {
  const [demands, setDemands] = useState(MOCK_MARKET_DEMAND);

  const getPharmacyNames = (ids: string[]) => {
    return ids.map(id => {
      const p = MOCK_PHARMACIES.find(ph => ph.id === id);
      return p ? p.name : 'Unknown';
    });
  };

  const handleSupply = (id: string) => {
    setDemands(prev => prev.map(d => 
      d.id === id ? { ...d, status: 'supplied' } : d
    ));
  };

  const getUrgencyColor = (urgency: string) => {
    switch (urgency) {
      case 'high': return 'text-red-600 bg-red-50 border-red-100';
      case 'medium': return 'text-amber-600 bg-amber-50 border-amber-100';
      default: return 'text-green-600 bg-green-50 border-green-100';
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Market Demand</h1>
          <p className="text-gray-500 mt-1">Aggregated 'Wanted Lists' from all network pharmacies.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
        <div className="bg-indigo-600 rounded-xl p-5 text-white shadow-lg shadow-indigo-200">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-indigo-200 text-sm font-medium">Top Requested</p>
              <h3 className="text-2xl font-bold mt-1">Amoxicillin</h3>
            </div>
            <TrendingUp className="text-indigo-200" />
          </div>
          <div className="mt-4 text-sm text-indigo-200">
            Requested by 3 pharmacies
          </div>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-4 border-b border-gray-200 bg-gray-50/50 flex gap-4">
          <div className="relative flex-1">
             <Search className="absolute left-3 top-2.5 h-4 w-4 text-gray-400" />
             <input 
              type="text"
              placeholder="Search medicines..."
              className="w-full pl-9 pr-4 py-2 border border-gray-300 rounded-lg text-sm focus:ring-indigo-500 focus:border-indigo-500"
             />
          </div>
          <select className="border border-gray-300 rounded-lg text-sm px-3 py-2 bg-white text-gray-700">
            <option>All Urgency</option>
            <option>High</option>
            <option>Medium</option>
            <option>Low</option>
          </select>
        </div>

        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Medicine Name</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Total Qty</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Urgency</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Requesting Pharmacies</th>
                <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {demands.map((item) => (
                <tr key={item.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="text-sm font-medium text-gray-900">{item.medicineName}</div>
                    <div className="text-xs text-gray-500">ID: {item.id}</div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="text-sm font-bold text-gray-900">{item.totalQuantity.toLocaleString()}</div>
                    <div className="text-xs text-gray-500">Units</div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${getUrgencyColor(item.urgency)}`}>
                      {item.urgency === 'high' && <AlertCircle size={12} className="mr-1" />}
                      {item.urgency.charAt(0).toUpperCase() + item.urgency.slice(1)}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-wrap gap-1">
                      {getPharmacyNames(item.requestingPharmacyIds).map((name, idx) => (
                        <span key={idx} className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-gray-100 text-gray-800">
                          {name}
                        </span>
                      ))}
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                    {item.status === 'supplied' ? (
                      <Badge variant="success">Supplied</Badge>
                    ) : (
                      <Button size="sm" variant="outline" onClick={() => handleSupply(item.id)}>
                        <PackageCheck size={14} className="mr-1" />
                        Mark Supplied
                      </Button>
                    )}
                  </td>
                </tr>
