import React, { useState } from 'react';
import { 
  LayoutDashboard, Building2, Radio, Globe, LogOut, Menu, 
  ShieldCheck, LockKeyhole, Store, MapPin, Mail, Key, X 
} from 'lucide-react';
import { MOCK_PHARMACIES, MOCK_DEMAND, MOCK_MESSAGES, Pharmacy, DemandItem, SystemMessage } from './data';
import { OverviewView, PharmaciesView, MarketRadarView, GlobalOperationsView, Button } from './Views';

type ViewType = 'overview' | 'pharmacies' | 'radar' | 'global';

function App() {
  // --- Global State ---
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');
  const [currentView, setCurrentView] = useState<ViewType>('overview');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // --- Data State (Mocking Supabase Tables) ---
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>(MOCK_PHARMACIES);
  const [demands, setDemands] = useState<DemandItem[]>(MOCK_DEMAND);
  const [messages, setMessages] = useState<SystemMessage[]>(MOCK_MESSAGES);

  // --- Modal State ---
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newPharm, setNewPharm] = useState({ name: '', location: '', email: '' });

  // --- Actions ---

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin === '1234') setIsAuthenticated(true);
    else setError('رمز الدخول خاطئ');
  };

  // Generate Unique Pharmacy Key & Password
  const generateCredentials = () => {
    const key = `RAHA-KEY-${Math.floor(1000 + Math.random() * 9000)}`;
    const pass = `PASS-${Math.floor(1000 + Math.random() * 9000)}`;
    return { key, pass };
  };

  const handleAddPharmacy = (e: React.FormEvent) => {
    e.preventDefault();
    const { key, pass } = generateCredentials();
    const newItem: Pharmacy = {
      id: crypto.randomUUID(), // Generates a proper UUID
      name: newPharm.name,
      location: newPharm.location,
      contact_email: newPharm.email,
      pharmacy_key: key,
      master_password: pass,
      status: 'active',
      joined_date: new Date().toISOString().split('T')[0],
      balance: 0
    };
    // In real app: await supabase.from('pharmacies').insert(newItem)
    setPharmacies([newItem, ...pharmacies]);
    setIsModalOpen(false);
    setNewPharm({ name: '', location: '', email: '' });
  };

  // Kill Switch Logic
  const togglePharmStatus = (id: string) => {
    // In real app: await supabase.from('pharmacies').update({ status: newStatus }).eq('id', id)
    setPharmacies(pharmacies.map(p => {
        if (p.id !== id) return p;
        const newStatus = p.status === 'active' ? 'suspended' : 'active';
        return { ...p, status: newStatus };
    }));
  };

  // Broadcast Message Logic
  const handleBroadcast = (content: string, priority: 'normal' | 'urgent') => {
    const newMsg: SystemMessage = {
        id: Date.now().toString(),
        content,
        priority,
        is_active: true,
        created_at: new Date().toISOString().split('T')[0]
    };
    // In real app: await supabase.from('system_messages').insert(newMsg)
    setMessages([newMsg, ...messages]);
    alert('تم إرسال الرسالة إلى جميع الأنظمة بنجاح');
  };

  // Global Price Update Logic
  const handlePriceUpdate = (barcode: string, newPrice: number) => {
    // In real app: 
    // await supabase.from('medicines').update({ price: newPrice }).eq('barcode', barcode)
    alert(`تم إرسال أمر تحديث السعر (${newPrice} SDG) للمنتج ${barcode} لجميع الصيدليات.`);
  };

  // --- Stats Calculation ---
  const stats = {
    totalPharmacies: pharmacies.length,
    activePharmacies: pharmacies.filter(p => p.status === 'active').length,
    balance: pharmacies.reduce((acc, p) => acc + p.balance, 0),
    demandCount: demands.length
  };

  // --- Render ---
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-2xl shadow-xl p-8">
          <div className="flex flex-col items-center mb-8">
            <div className="w-16 h-16 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center mb-4"><ShieldCheck size={32} /></div>
            <h1 className="text-2xl font-bold text-gray-900">Raha Control Center</h1>
            <p className="text-gray-500 text-sm mt-2">SaaS Super Admin - Pro Edition</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-6">
            <div className="relative">
              <input type="password" value={pin} onChange={(e) => setPin(e.target.value)} maxLength={4}
                className="block w-full text-center py-3 border border-gray-300 rounded-lg focus:ring-indigo-500 text-2xl tracking-widest placeholder-gray-300" placeholder="••••" />
              <LockKeyhole className="absolute top-4 right-4 text-gray-400 w-5 h-5" />
            </div>
            {error && <p className="text-red-600 text-sm text-center">{error}</p>}
            <button type="submit" className="w-full bg-indigo-600 text-white py-3 rounded-lg hover:bg-indigo-700 font-bold transition">دخول آمن</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden">
      {/* Sidebar */}
      <aside className={`fixed inset-y-0 right-0 z-50 w-64 bg-indigo-900 text-white transform transition-transform duration-200 lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="h-16 flex items-center px-6 border-b border-indigo-800">
          <div className="flex items-center gap-2 font-bold text-xl">
            <div className="w-8 h-8 bg-indigo-500 rounded-lg flex items-center justify-center text-white text-sm">Pro</div>
            <span>Raha <span className="text-indigo-300 font-normal">SaaS</span></span>
          </div>
        </div>
        <nav className="p-4 space-y-1">
          <button onClick={() => { setCurrentView('overview'); setIsSidebarOpen(false); }} className={`w-full flex items-center gap-3 px-3 py-3 rounded-lg transition ${currentView === 'overview' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800'}`}>
            <LayoutDashboard size={20} /> نظرة عامة
          </button>
          <button onClick={() => { setCurrentView('pharmacies'); setIsSidebarOpen(false); }} className={`w-full flex items-center gap-3 px-3 py-3 rounded-lg transition ${currentView === 'pharmacies' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800'}`}>
            <Building2 size={20} /> إدارة المشتركين
          </button>
          <button onClick={() => { setCurrentView('radar'); setIsSidebarOpen(false); }} className={`w-full flex items-center gap-3 px-3 py-3 rounded-lg transition ${currentView === 'radar' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800'}`}>
            <Radio size={20} /> رادار السوق
          </button>
          <button onClick={() => { setCurrentView('global'); setIsSidebarOpen(false); }} className={`w-full flex items-center gap-3 px-3 py-3 rounded-lg transition ${currentView === 'global' ? 'bg-indigo-800 text-white' : 'text-indigo-200 hover:bg-indigo-800'}`}>
            <Globe size={20} /> عمليات عالمية
          </button>
          <div className="pt-8 mt-4 border-t border-indigo-800">
            <button onClick={() => setIsAuthenticated(false)} className="w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-red-300 hover:bg-indigo-800">
              <LogOut size={20} /> تسجيل خروج
            </button>
          </div>
        </nav>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 lg:mr-64 transition-all duration-200 h-full">
        <header className="bg-white border-b border-gray-200 h-16 flex items-center justify-between px-4 lg:hidden flex-shrink-0">
           <span className="font-bold text-indigo-900">Raha SaaS Admin</span>
           <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-gray-100 rounded-md"><Menu size={24} /></button>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:p-8">
          {currentView === 'overview' && <OverviewView stats={stats} />}
          {currentView === 'pharmacies' && <PharmaciesView data={pharmacies} onToggleStatus={togglePharmStatus} onAddClick={() => setIsModalOpen(true)} />}
          {currentView === 'radar' && <MarketRadarView data={demands} />}
          {currentView === 'global' && <GlobalOperationsView messages={messages} onBroadcast={handleBroadcast} onPriceUpdate={handlePriceUpdate} />}
        </main>
      </div>

      {/* Add Pharmacy Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white rounded-t-2xl sm:rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-in slide-in-from-bottom duration-300">
            <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
              <h3 className="text-lg font-bold text-gray-900">تسجيل مستأجر جديد (New Tenant)</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600"><X size={20} /></button>
            </div>
            <form onSubmit={handleAddPharmacy} className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">اسم الصيدلية</label>
                <div className="relative">
                  <Store className="absolute right-3 top-2.5 h-4 w-4 text-gray-400" />
                  <input required type="text" className="w-full pr-9 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500" value={newPharm.name} onChange={e => setNewPharm({...newPharm, name: e.target.value})} placeholder="مثال: صيدلية النور" />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">الموقع</label>
