import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, Building2, Radio, Globe, LogOut, Menu, 
  ShieldCheck, LockKeyhole, Store, MapPin, Mail, Key, X, Loader2 
} from 'lucide-react';
import { supabase } from './supabase';
import { Pharmacy, DemandItem, SystemMessage, CHART_DATA } from './data';
import { OverviewView, PharmaciesView, MarketRadarView, GlobalOperationsView, Button } from './Views';

type ViewType = 'overview' | 'pharmacies' | 'radar' | 'global';

function App() {
  // --- Global State ---
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');
  const [currentView, setCurrentView] = useState<ViewType>('overview');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // --- Data State ---
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>([]);
  const [demands, setDemands] = useState<DemandItem[]>([]);
  const [messages, setMessages] = useState<SystemMessage[]>([]);

  // --- Modal State ---
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newPharm, setNewPharm] = useState({ name: '', location: '', email: '' });

  // --- Fetch Data from Supabase ---
  const fetchData = async () => {
    setIsLoading(true);
    try {
      // 1. Fetch Pharmacies
      const { data: pharmData, error: pharmError } = await supabase
        .from('pharmacies')
        .select('*')
        .order('joined_date', { ascending: false });

      if (pharmError) throw pharmError;

      // 2. Fetch Demands (Wanted List)
      const { data: demandData, error: demandError } = await supabase
        .from('wanted_list')
        .select('*')
        .eq('status', 'pending')
        .order('created_at', { ascending: false });

      if (demandError) throw demandError;

      // 3. Fetch System Messages
      const { data: msgData, error: msgError } = await supabase
        .from('system_messages')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(10);

      if (msgError) throw msgError;

      // Map demand data to include pharmacy names (Client-side join)
      const mappedDemands = (demandData || []).map((d: any) => {
        const ph = (pharmData || []).find((p: any) => p.id === d.pharmacy_id);
        return {
          ...d,
          pharmacy_name: ph ? ph.name : 'Unknown Pharmacy'
        };
      });

      setPharmacies(pharmData || []);
      setDemands(mappedDemands);
      setMessages(msgData || []);

    } catch (err: any) {
      console.error('Error fetching data:', err.message);
      // alert('حدث خطأ أثناء جلب البيانات من الخادم');
    } finally {
      setIsLoading(false);
    }
  };

  // Initial Load
  useEffect(() => {
    if (isAuthenticated) {
      fetchData();
    }
  }, [isAuthenticated]);

  // --- Actions ---

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin === '1234') setIsAuthenticated(true);
    else setError('رمز الدخول خاطئ');
  };

  const generateCredentials = () => {
    const key = `RAHA-${Math.floor(100000 + Math.random() * 900000)}`;
    const pass = `P${Math.floor(1000 + Math.random() * 9000)}`;
    return { key, pass };
  };

  // 1. Add New Pharmacy (Tenant)
  const handleAddPharmacy = async (e: React.FormEvent) => {
    e.preventDefault();
    const { key, pass } = generateCredentials();

    // Optimistic UI update not ideal here due to ID generation, waiting for DB
    try {
      const { data, error } = await supabase.from('pharmacies').insert([
        {
          name: newPharm.name,
          location: newPharm.location,
          contact_email: newPharm.email,
          pharmacy_key: key,
          master_password: pass,
          status: 'active',
          balance: 0,
          joined_date: new Date().toISOString()
        }
      ]).select();

      if (error) throw error;
      if (data) {
        setPharmacies([data[0] as Pharmacy, ...pharmacies]);
        setIsModalOpen(false);
        setNewPharm({ name: '', location: '', email: '' });
        alert(`تم إنشاء الصيدلية بنجاح!\nالمفتاح: ${key}\nكلمة المرور: ${pass}`);
