  // 2. Kill Switch Logic
  const togglePharmStatus = async (id: string) => {
    const pharmacy = pharmacies.find(p => p.id === id);
    if (!pharmacy) return;

    const newStatus = pharmacy.status === 'active' ? 'suspended' : 'active';
    const confirmMsg = newStatus === 'suspended' 
