      : 'هل تريد إعادة تفعيل النظام للصيدلية؟';

    if (!window.confirm(confirmMsg)) return;

    try {
      const { error } = await supabase
        .from('pharmacies')
        .update({ status: newStatus })
        .eq('id', id);

