-- Raha SaaS Multi-Tenancy Migration

-- 1. Create Pharmacies Registry
CREATE TABLE IF NOT EXISTS pharmacies (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    pharmacy_key TEXT UNIQUE NOT NULL,
    name TEXT NOT NULL,
    master_password TEXT NOT NULL,
    status TEXT DEFAULT 'active' CHECK (status IN ('active', 'suspended')),
    joined_date TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 2. Create System Messages for Broadcast
CREATE TABLE IF NOT EXISTS system_messages (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    content TEXT NOT NULL,
    type TEXT DEFAULT 'info',
    active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 3. Update Existing Tables with pharmacy_id
-- We assume these tables exist from previous migrations
DO $$ 
BEGIN 
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='medicines' AND column_name='pharmacy_id') THEN
        ALTER TABLE medicines ADD COLUMN pharmacy_id UUID REFERENCES pharmacies(id);
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='sales' AND column_name='pharmacy_id') THEN
        ALTER TABLE sales ADD COLUMN pharmacy_id UUID REFERENCES pharmacies(id);
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='expenses' AND column_name='pharmacy_id') THEN
        ALTER TABLE expenses ADD COLUMN pharmacy_id UUID REFERENCES pharmacies(id);
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='wanted_list' AND column_name='pharmacy_id') THEN
        ALTER TABLE wanted_list ADD COLUMN pharmacy_id UUID REFERENCES pharmacies(id);
    END IF;
END $$;

-- 4. Enable RLS on all tables
ALTER TABLE pharmacies ENABLE ROW LEVEL SECURITY;
ALTER TABLE medicines ENABLE ROW LEVEL SECURITY;
ALTER TABLE sales ENABLE ROW LEVEL SECURITY;
ALTER TABLE expenses ENABLE ROW LEVEL SECURITY;
ALTER TABLE wanted_list ENABLE ROW LEVEL SECURITY;
ALTER TABLE system_messages ENABLE ROW LEVEL SECURITY;

-- 5. Create RLS Policies for Tenant Isolation
-- These policies assume the application sets 'app.pharmacy_id' in the session context

DROP POLICY IF EXISTS "Pharmacy isolation" ON medicines;
CREATE POLICY "Pharmacy isolation" ON medicines
    FOR ALL USING (pharmacy_id::text = current_setting('app.pharmacy_id', true));

DROP POLICY IF EXISTS "Pharmacy isolation" ON sales;
CREATE POLICY "Pharmacy isolation" ON sales
    FOR ALL USING (pharmacy_id::text = current_setting('app.pharmacy_id', true));

DROP POLICY IF EXISTS "Pharmacy isolation" ON expenses;
CREATE POLICY "Pharmacy isolation" ON expenses
    FOR ALL USING (pharmacy_id::text = current_setting('app.pharmacy_id', true));

DROP POLICY IF EXISTS "Pharmacy isolation" ON wanted_list;
CREATE POLICY "Pharmacy isolation" ON wanted_list
    FOR ALL USING (pharmacy_id::text = current_setting('app.pharmacy_id', true));

-- 6. Super Admin Access Policy (Broadcast reads for everyone)
DROP POLICY IF EXISTS "Public read for system messages" ON system_messages;
CREATE POLICY "Public read for system messages" ON system_messages
    FOR SELECT USING (active = TRUE);

-- 7. Pharmacy Status Check View (Optional helper)
CREATE OR REPLACE VIEW active_pharmacies AS
SELECT id, status FROM pharmacies WHERE status = 'active';

