const MarketRadar = ({ demands }: { demands: DemandItem[] }) => {
  // Aggregation Logic for "Smart Insights"
  const topMedicines = useMemo(() => {
    const counts: Record<string, number> = {};
    demands.forEach(d => {
      counts[d.medicine_name] = (counts[d.medicine_name] || 0) + d.quantity;
    });
    return Object.entries(counts)
      .sort(([, a], [, b]) => b - a)
      .slice(0, 5)
      .map(([name, count]) => ({ name, count }));
  }, [demands]);

  const handleExport = () => {
    const exportData = demands.map(d => ({
      Medicine: d.medicine_name,
      Quantity: d.quantity,
      Urgency: d.urgency,
      Pharmacy: d.pharmacy_name,
      Date: new Date(d.created_at).toLocaleDateString()
    }));
    downloadCSV(exportData, 'market_demand_report.csv');
