// --- MAIN APP ---

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [pin, setPin] = useState('');
  const [view, setView] = useState<ViewType>('overview');
  const [loading, setLoading] = useState(false);
  const [isSidebarOpen, setSidebarOpen] = useState(true); // Default open on desktop

  // Data
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>([]);
  const [demands, setDemands] = useState<DemandItem[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [logs, setLogs] = useState<AuditLog[]>([]);

  // Modals
  const [showAddModal, setShowAddModal] = useState(false);
  const [newPharm, setNewPharm] = useState({ name: '', location: '', email: '' });

  // --- LOGIC ---

  const addLog = (action: string, details: string) => {
    const newLog: AuditLog = {
      id: Math.random().toString(36),
      action,
      details,
      timestamp: new Date().toLocaleTimeString(),
      user: 'Super Admin'
    };
    setLogs(prev => [newLog, ...prev]);
  };

  const fetchData = async () => {
    setLoading(true);
    try {
      const [phRes, demRes, salesRes] = await Promise.all([
        supabase.from('pharmacies').select('*'),
        supabase.from('wanted_list').select('*').eq('status', 'pending'),
        supabase.from('sales').select('*').limit(1000)
      ]);

      if (phRes.data) {
        // Auto-suspend logic check
        const phData = phRes.data.map((p: any) => ({
          ...p,
          // Simulate auto-suspend locally if balance < 0 (Real impl would be backend trigger)
          status: p.balance < 0 ? 'suspended' : p.status
        }));
        setPharmacies(phData);
      }

      if (demRes.data) {
        // Join logic manually since no simple join in supabase-js without foreign keys setup
        const joinedDemands = demRes.data.map((d: any) => ({
          ...d,
          pharmacy_name: phRes.data?.find((p:any) => p.id === d.pharmacy_id)?.name || 'Unknown'
        }));
        setDemands(joinedDemands);
      }

      if (salesRes.data) setSales(salesRes.data);

    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (isAuthenticated) {
      fetchData();
      // Setup Realtime
      const channel = supabase.channel('main')
        .on('postgres_changes', { event: '*', schema: 'public' }, () => fetchData())
        .subscribe();
      return () => { supabase.removeChannel(channel) };
    }
  }, [isAuthenticated]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin === '1234') setIsAuthenticated(true);
    else alert('رمز خاطئ');
  };

  const handleAddPharmacy = async () => {
    const key = `RAHA-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;
    const { error } = await supabase.from('pharmacies').insert([{
      name: newPharm.name,
      location: newPharm.location,
      contact_email: newPharm.email,
      pharmacy_key: key,
      status: 'active',
      balance: 0,
      joined_date: new Date().toISOString()
    }]);

    if (!error) {
      alert(`تم إضافة الصيدلية.\nالمفتاح: ${key}`);
      setShowAddModal(false);
      addLog('إضافة صيدلية', `تم إضافة ${newPharm.name}`);
      fetchData();
    }
  };

  const toggleStatus = async (id: string) => {
    const p = pharmacies.find(x => x.id === id);
    if (!p) return;
    const newStatus = p.status === 'active' ? 'suspended' : 'active';

    if (confirm(newStatus === 'suspended' ? 'هل أنت متأكد من قفل النظام؟' : 'تفعيل النظام؟')) {
      await supabase.from('pharmacies').update({ status: newStatus }).eq('id', id);
      addLog('تغيير حالة', `${p.name} -> ${newStatus}`);
      fetchData();
    }
  };

  const updatePrice = async (barcode: string, price: string) => {
    if (!barcode || !price) return;
    if (confirm(`تعميم السعر ${price} للباركود ${barcode}؟`)) {
       const { error } = await supabase.from('medicines').update({ price: Number(price) }).eq('barcode', barcode);
       if (!error) {
         alert('تم التحديث بنجاح');
         addLog('توحيد سعر', `Barcode: ${barcode} -> ${price} SDG`);
       } else {
         alert('فشل التحديث. تأكد من وجود الباركود.');
       }
    }
  };

  const broadcast = async (content: string, priority: Priority) => {
    if (!content) return;
    await supabase.from('system_messages').insert([{ content, priority, is_active: true }]);
    alert('تم الإرسال');
    addLog('بث رسالة', `Priority: ${priority}`);
  };

  if (!isAuthenticated) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-slate-950 relative overflow-hidden">
        {/* Animated Background Effect */}
        <div className="absolute inset-0 overflow-hidden">
           <div className="absolute -top-[50%] -left-[50%] w-[200%] h-[200%] bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-900/20 via-slate-950 to-slate-950 animate-spin-slow opacity-50"></div>
        </div>

        <GlassCard className="w-full max-w-md p-8 relative z-10 border-indigo-500/20 shadow-2xl shadow-indigo-900/20">
          <div className="flex justify-center mb-6">
            <div className="w-20 h-20 rounded-2xl bg-indigo-600 flex items-center justify-center shadow-lg shadow-indigo-600/50">
               <ShieldCheck size={40} className="text-white" />
            </div>
          </div>
          <h1 className="text-3xl font-bold text-center text-white mb-2">RAHA ADMIN</h1>
          <p className="text-center text-slate-400 mb-8 text-sm tracking-widest uppercase">Secure Gateway</p>

          <form onSubmit={handleLogin} className="space-y-6">
            <div className="relative">
              <input 
                type="password" 
                value={pin} onChange={e => setPin(e.target.value)}
                maxLength={4}
                className="w-full bg-slate-900/50 border border-slate-700 text-center text-3xl tracking-[1em] text-white py-4 rounded-xl focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 outline-none transition-all placeholder:text-slate-700 font-bold"
                placeholder="••••"
                autoFocus
              />
              <LockKeyhole className="absolute right-4 top-5 text-slate-600" size={20} />
            </div>
            <button type="submit" className="w-full bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-4 rounded-xl shadow-lg shadow-indigo-900/40 transition-all active:scale-95">
              ACCESS MISSION CONTROL
            </button>
          </form>
        </GlassCard>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 font-sans overflow-hidden">
      {/* Sidebar */}
      <motion.aside 
        initial={{ x: -300 }} animate={{ x: 0 }}
        className="w-72 bg-slate-900 border-l border-slate-800 flex flex-col z-50 shadow-2xl"
      >
        <div className="h-20 flex items-center px-6 border-b border-slate-800 gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold shadow-lg shadow-indigo-600/30">R</div>
          <div>
            <h1 className="font-bold text-white text-lg">Raha SaaS</h1>
            <div className="text-[10px] text-emerald-400 font-mono flex items-center gap-1">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> ONLINE
            </div>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          {[
            { id: 'overview', icon: LayoutDashboard, label: 'لوحة القيادة' },
            { id: 'pharmacies', icon: Building2, label: 'المشتركين' },
            { id: 'radar', icon: Radio, label: 'رادار السوق' },
            { id: 'global', icon: Globe, label: 'مركز التحكم' },
          ].map(item => (
            <button
              key={item.id}
              onClick={() => setView(item.id as ViewType)}
              className={`w-full flex items-center gap-4 px-4 py-3.5 rounded-xl transition-all ${view === item.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/40' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
            >
