function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [pin, setPin] = useState('');
  const [view, setView] = useState<ViewType>('overview');
  const [loading, setLoading] = useState(false);

  const [pharmacies, setPharmacies] = useState<Pharmacy[]>([]);
  const [demands, setDemands] = useState<DemandItem[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [logs, setLogs] = useState<AuditLog[]>([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [newPharm, setNewPharm] = useState({ name: '', location: '', email: '' });

  const addLog = (action: string, details: string) => {
    setLogs(prev => [{ id: Math.random().toString(), action, details, timestamp: new Date().toLocaleTimeString(), user: 'Super Admin' }, ...prev]);
  };

  const fetchData = async () => {
    setLoading(true);
    try {
      const [phRes, demRes, salesRes] = await Promise.all([
        supabase.from('pharmacies').select('*'),
        supabase.from('wanted_list').select('*').eq('status', 'pending'),
        supabase.from('sales').select('*').limit(1000)
      ]);

      if (phRes.data) setPharmacies(phRes.data.map((p: any) => ({ ...p, status: p.balance < 0 ? 'suspended' : p.status })));
      if (demRes.data) setDemands(demRes.data.map((d: any) => ({ ...d, pharmacy_name: phRes.data?.find((p:any) => p.id === d.pharmacy_id)?.name || 'Unknown' })));
      if (salesRes.data) setSales(salesRes.data);
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  useEffect(() => {
    if (isAuthenticated) {
      fetchData();
      const channel = supabase.channel('main').on('postgres_changes', { event: '*', schema: 'public' }, () => fetchData()).subscribe();
      return () => { supabase.removeChannel(channel) };
