        <div className="flex gap-2">
            <Button variant="outline" icon={Plus} onClick={() => setAddMode(!addMode)}>إضافة يدوي</Button>
            <Button variant="outline" icon={FileSpreadsheet} onClick={handleExport}>تصدير Excel</Button>
