      {addMode && (
         <GlassCard className="border-indigo-500/50 bg-indigo-900/10 animate-in slide-in-from-top duration-300">
            <h3 className="text-white font-bold mb-4 flex items-center gap-2"><ShieldAlert className="text-indigo-400"/> إضافة ناقص جديد (Smart Check Active)</h3>
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
               <div>
                  <label className="text-xs text-slate-400 block mb-1">اسم الدواء</label>
                  <input className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2 text-white" value={newItem.name} onChange={e=>setNewItem({...newItem, name: e.target.value})} placeholder="Ex: Panadol" />
