function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [pin, setPin] = useState('');
  const [view, setView] = useState<ViewType>('overview');
  const [loading, setLoading] = useState(false);

  const [pharmacies, setPharmacies] = useState<Pharmacy[]>([]);
  const [demands, setDemands] = useState<DemandItem[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [logs, setLogs] = useState<AuditLog[]>([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [newPharm, setNewPharm] = useState({ name: '', location: '', email: '' });

  const addLog = (action: string, details: string) => {
    setLogs(prev => [{ id: Math.random().toString(), action, details, timestamp: new Date().toLocaleTimeString(), user: 'Super Admin' }, ...prev]);
  };

  const fetchData = async () => {
    setLoading(true);
    try {
      const [phRes, demRes, salesRes] = await Promise.all([
        supabase.from('pharmacies').select('*'),
        supabase.from('wanted_list').select('*').eq('status', 'pending'),
        supabase.from('sales').select('*').limit(1000)
      ]);

      if (phRes.data) setPharmacies(phRes.data.map((p: any) => ({ ...p, status: p.balance < 0 ? 'suspended' : p.status })));
      if (demRes.data) setDemands(demRes.data.map((d: any) => ({ ...d, pharmacy_name: phRes.data?.find((p:any) => p.id === d.pharmacy_id)?.name || 'Unknown' })));
      if (salesRes.data) setSales(salesRes.data);
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  useEffect(() => {
    if (isAuthenticated) {
      fetchData();
      const channel = supabase.channel('main').on('postgres_changes', { event: '*', schema: 'public' }, () => fetchData()).subscribe();
      return () => { supabase.removeChannel(channel) };
    }
  }, [isAuthenticated]);

  const handleLogin = (e: React.FormEvent) => { 
      e.preventDefault(); 
      const savedPin = localStorage.getItem('raha_admin_pin') || '1234';
      if (pin === savedPin) setIsAuthenticated(true); else alert('رمز خاطئ'); 
  };

  const handleAddPharmacy = async () => {
    const key = `RAHA-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;
    const { error } = await supabase.from('pharmacies').insert([{ name: newPharm.name, location: newPharm.location, contact_email: newPharm.email, pharmacy_key: key, status: 'active', balance: 0, joined_date: new Date().toISOString() }]);
    if (!error) { alert(`تمت الإضافة. المفتاح: ${key}`); setShowAddModal(false); addLog('إضافة صيدلية', newPharm.name); fetchData(); }
  };
  const toggleStatus = async (id: string) => {
    const p = pharmacies.find(x => x.id === id);
    if (!p) return;
    const newStatus = p.status === 'active' ? 'suspended' : 'active';
    if (confirm('تأكيد الإجراء؟')) { await supabase.from('pharmacies').update({ status: newStatus }).eq('id', id); addLog('تغيير حالة', `${p.name} -> ${newStatus}`); fetchData(); }
  };
  const updatePrice = async (barcode: string, price: string) => {
    if (!barcode || !price) return;
    if (confirm(`تعميم السعر ${price}؟`)) { await supabase.from('medicines').update({ price: Number(price) }).eq('barcode', barcode); addLog('توحيد سعر', barcode); alert('تم'); }
  };
  const broadcast = async (content: string, priority: Priority) => {
    if (!content) return;
    await supabase.from('system_messages').insert([{ content, priority, is_active: true }]); addLog('بث رسالة', priority); alert('تم');
  };
  const updateMasterPass = async (id: string, pass: string) => {
      await supabase.from('pharmacies').update({ master_password: pass }).eq('id', id);
      addLog('تغيير كلمة مرور', `ID: ${id}`);
      alert('تم التحديث');
  };

  if (!isAuthenticated) return (
    <div className="h-screen w-full flex items-center justify-center bg-slate-950 relative overflow-hidden">
        <GlassCard className="w-full max-w-md p-8 relative z-10 border-indigo-500/20 shadow-2xl">
          <div className="flex justify-center mb-6"><div className="w-20 h-20 rounded-2xl bg-indigo-600 flex items-center justify-center shadow-lg"><ShieldCheck size={40} className="text-white" /></div></div>
