const MarketRadar = ({ demands, pharmacies }: { demands: DemandItem[], pharmacies: Pharmacy[] }) => {
  const [addMode, setAddMode] = useState(false);
  const [newItem, setNewItem] = useState({ name: '', qty: '', pharm_id: '' });

  const handleAddShortage = async () => {
     // Smart Radar Logic: Check Duplicates
     const exists = demands.find(d => 
        d.medicine_name.toLowerCase() === newItem.name.toLowerCase() && 
        d.pharmacy_id === newItem.pharm_id
     );

     if (exists) {
        alert('تنبيه الرادار الذكي: هذا الصنف مسجل بالفعل كـ "ناقص" لهذه الصيدلية. لا يمكن التكرار.');
        return;
     }

     const { error } = await supabase.from('wanted_list').insert([{
        medicine_name: newItem.name,
        quantity: Number(newItem.qty),
        pharmacy_id: newItem.pharm_id,
        status: 'pending',
        urgency: 'high',
        created_at: new Date().toISOString()
     }]);

     if(!error) {
        alert('تم إضافة الناقص بنجاح');
        setAddMode(false);
        setNewItem({ name: '', qty: '', pharm_id: '' });
     } else {
        alert('خطأ في الإضافة');
     }
  };

  const topMedicines = useMemo(() => {
    const counts: Record<string, number> = {};
    demands.forEach(d => { counts[d.medicine_name] = (counts[d.medicine_name] || 0) + d.quantity; });
    return Object.entries(counts).sort(([, a], [, b]) => b - a).slice(0, 5).map(([name, count]) => ({ name, count }));
  }, [demands]);

  const handleExport = () => {
    const exportData = demands.map(d => ({ Medicine: d.medicine_name, Quantity: d.quantity, Urgency: d.urgency, Pharmacy: d.pharmacy_name }));
    downloadCSV(exportData, 'market_demand.csv');
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2"><Radio className="text-indigo-400 animate-pulse" /> رادار السوق</h2>
        <div className="flex gap-2">
            <Button variant="outline" icon={Plus} onClick={() => setAddMode(!addMode)}>إضافة يدوي</Button>
            <Button variant="outline" icon={FileSpreadsheet} onClick={handleExport}>تصدير Excel</Button>
        </div>
      </div>

      {addMode && (
         <GlassCard className="border-indigo-500/50 bg-indigo-900/10 animate-in slide-in-from-top duration-300">
            <h3 className="text-white font-bold mb-4 flex items-center gap-2"><ShieldAlert className="text-indigo-400"/> إضافة ناقص جديد (Smart Check Active)</h3>
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
               <div>
                  <label className="text-xs text-slate-400 block mb-1">اسم الدواء</label>
                  <input className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2 text-white" value={newItem.name} onChange={e=>setNewItem({...newItem, name: e.target.value})} placeholder="Ex: Panadol" />
               </div>
               <div>
                  <label className="text-xs text-slate-400 block mb-1">الكمية</label>
                  <input type="number" className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2 text-white" value={newItem.qty} onChange={e=>setNewItem({...newItem, qty: e.target.value})} placeholder="0" />
